# --- plot helper (hidden) — Moon descents at different thrusts ---
def __descend(thrust, dt, steps, every):
    g = 1.62; h = 50.0; v = 0.0; t = 0.0
    pts = [[0.0, 50.0]]
    for i in range(steps):
        v += (thrust - g) * dt
        h += v * dt; t += dt
        if h <= 0:
            pts.append([round(t, 2), 0.0]); break
        if i % every == 0:
            pts.append([round(t, 2), round(h, 2)])
    return pts

def __plot(_):
    return [
        {"name": "engine off (0.0) — crash", "points": __descend(0.0, 0.05, 3000, 20), "highlight": False},
        {"name": "weak (1.0)", "points": __descend(1.0, 0.05, 3000, 20), "highlight": False},
        {"name": "strong (1.61) — gentle glide", "points": __descend(1.61, 0.05, 3000, 20), "highlight": True},
    ]
